#include <bits/stdc++.h>
using namespace std;
int main(){
    long long n,x;
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>x;
        if(x==1)cout<<-1;
        else if(x==2){
            cout<<1;
        }
        else if(x==3){
            cout<<7;
        }
        else if(x==4){
            cout<<4;
        }
        else if(x==5){
            cout<<2;
        }
        else if(x==6){
            cout<<6;
        }
        else if(x==7){
            cout<<8;
        }
        else if(x%7==0){
            for(int i=0;i<x/7;i++){
                cout<<8;
            }
        }
        else if(x%7==1){
            cout<<10;
            for(int i=0;i<(x-8)/7;i++){
                cout<<8;
            }
        }
        else if(x%7==2){
            cout<<1;
            for(int i=0;i<(x-2)/7;i++){
                cout<<8;
            }
        }
        else if(x%7==3){
            cout<<2;
            if(x/7==1){
                cout<<2;
            }
            else if(x/7==2){
            	cout<<"00";
			}
            else{
                for(int i=0;i<(x-17)/7;i++){
                    cout<<8;
                }
            }
        }
        else if(x%7==4){
            cout<<20;
            for(int i=0;i<(x-11)/7;i++){
                    cout<<8;
                }
        }
        else if(x%7==5){
            cout<<2;
            for(int i=0;i<(x-5)/7;i++){
                    cout<<8;
                }
        }
        else if(x%7==6){
            cout<<6;
            for(int i=0;i<(x-6)/7;i++){
                    cout<<8;
                }
        }
        cout<<endl;
    }
    return 0;
}
